import { MinPriorityQueue } from 'datastructures-js/priority-queue';

function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const directions = [[0, 1], [1, 0]]; // right and down

    const heap = new MinPriorityQueue({ priority: (item) => item[0] });
    heap.enqueue([0, 0, 0, k]);

    const visited = new Map();
    visited.set(`${0},${0},${k}`, 0);

    while (!heap.isEmpty()) {
        const [currentCost, i, j, remainingTeleports] = heap.dequeue().element;

        if (i === m - 1 && j === n - 1) {
            return currentCost;
        }

        const key = `${i},${j},${remainingTeleports}`;
        if (visited.get(key) < currentCost) {
            continue;
        }

        // Normal moves
        for (const [di, dj] of directions) {
            const ni = i + di;
            const nj = j + dj;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                const newCost = currentCost + grid[ni][nj];
                const newKey = `${ni},${nj},${remainingTeleports}`;
                if (!visited.has(newKey) || newCost < visited.get(newKey)) {
                    visited.set(newKey, newCost);
                    heap.enqueue([newCost, ni, nj, remainingTeleports]);
                }
            }
        }

        // Teleport moves
        if (remainingTeleports > 0) {
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if ((x !== i || y !== j) && grid[x][y] <= grid[i][j]) {
                        const newKey = `${x},${y},${remainingTeleports - 1}`;
                        if (!visited.has(newKey) || currentCost < visited.get(newKey)) {
                            visited.set(newKey, currentCost);
                            heap.enqueue([currentCost, x, y, remainingTeleports - 1]);
                        }
                    }
                }
            }
        }
    }

    return -1; // Should not reach here if the grid is valid
}
